// Build date range (last 7 days)
const days = $json.days_window;
const end = new Date();
const start = new Date(end.getTime() - days * 86400000);
const fmt = d => d.toISOString().slice(0, 10);
return [{ json: { ...$json, since: fmt(start), until: fmt(end) } }];

// Parse ROAS, sort, return top 20% and bottom 20% (for pattern contrast)
const data = $json.data || [];
const topPct = $('Config').first().json.top_percent;

const withRoas = data.map(d => {
  const roasArr = d.purchase_roas || [];
  const roas = roasArr.length ? parseFloat(roasArr[0].value) : 0;
  return { ...d, roas: isNaN(roas) ? 0 : roas };
}).filter(d => parseFloat(d.spend) > 0);

withRoas.sort((a, b) => b.roas - a.roas);

const n = withRoas.length;
const topN = Math.max(1, Math.ceil(n * topPct));
const top = withRoas.slice(0, topN);
const bottom = withRoas.slice(-topN);

return [{ json: { top, bottom, total_ads: n, week_ending: $('Build Date Range').first().json.until } }];

// Append daily summary rows to CampaignMetrics (one row per ad, weekly aggregate)
const topBottom = $json;
const rows = [];
for (const ad of [...topBottom.top, ...topBottom.bottom]) {
  const purchases = (ad.actions || []).find(a => a.action_type === 'purchase')?.value || 0;
  rows.push({
    json: {
      name: `${ad.ad_name || ad.ad_id} (week ${topBottom.week_ending})`,
      channel: 'meta_ads',
      entity_type: 'ad',
      entity_id: ad.ad_id,
      date: topBottom.week_ending,
      period: 'weekly',
      spend: parseFloat(ad.spend) || 0,
      impressions: parseInt(ad.impressions) || 0,
      clicks: parseInt(ad.clicks) || 0,
      conversions: parseInt(purchases) || 0,
      ctr: parseFloat(ad.ctr) || 0,
      cpa: parseFloat(ad.cpc) || 0,
      roas: ad.roas || 0,
      notes: ad.adset_name + ' / ' + ad.campaign_name,
    }
  });
}
return rows;

