const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let patterns;
try {
  patterns = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  patterns = { hook_patterns: [], cta_patterns: [], emotional_triggers: [], avoid_patterns: [], summary: '' };
}
return [{ json: patterns }];

// Bundle patterns + content seeds for variant generation
const patterns = $('Parse Patterns').item.json;
const posts = $input.all().map(p => {
  const props = p.json.properties || {};
  return {
    title: props.Name?.title?.[0]?.plain_text || '',
    meta_desc: props.meta_desc?.rich_text?.[0]?.plain_text || '',
    target_keyword: props.target_keyword?.select?.name || '',
    url: props.published_url?.url || '',
  };
}).filter(p => p.title);

return [{ json: { patterns, content_seeds: posts } }];

