const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  return [];
}
const variants = parsed.variants || [];
const patterns = $('Parse Patterns').item.json;
const weekEnding = $('Top/Bottom 20%').first().json.week_ending;

return variants.map((v, i) => ({
  json: {
    index: i + 1,
    week_ending: weekEnding,
    title: `Meta Ad — ${v.headline?.slice(0, 50) || ('Variant ' + (i+1))}`,
    headline: v.headline || '',
    body: v.body || '',
    cta: v.cta || 'Learn More',
    pattern_used: v.pattern_used || patterns.summary?.slice(0, 100) || '',
  }
}));

const variants = $input.all().map(i => i.json);
const patterns = $('Parse Patterns').item.json;

let text = `🎯 *주간 광고 카피 변형 ${variants.length}개 준비*
_지난 주 Top 20% 패턴 기반_

`;
text += `*이번 주 인사이트*: ${patterns.summary}

`;
text += `*Top 3 변형 (검토 우선)*:
`;
variants.slice(0, 3).forEach((v, i) => {
  text += `
${i+1}. *${v.headline}*
   ${v.body}
   _CTA: ${v.cta} · 패턴: ${v.pattern_used.slice(0, 50)}_
`;
});
text += `
_전체 ${variants.length}개는 Notion ContentDrafts (channel=meta_ad, status=review)_`;
return [{ json: { text } }];
